function star_pnt_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('star_pnt');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	// automatic iittnif_id if passed as filterer
	if(Request::val('filterer_iittnif_id')) {
		$_REQUEST['iittnif_id'] = Request::val('filterer_iittnif_id');
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'name_of_the_candidate' => Request::val('name_of_the_candidate', ''),
		'institute' => Request::val('institute', ''),
		'workspace' => Request::val('workspace', ''),
		'year_and_department' => Request::val('year_and_department', ''),
		'project_title' => br2nl(Request::val('project_title', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];


	// automatic iittnif_id if passed as filterer
	if(Request::val('filterer_iittnif_id')) {
		$data['iittnif_id'] = Request::val('filterer_iittnif_id');
	}
	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('star_pnt', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		star_pnt_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function star_pnt_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function star_pnt_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('star_pnt', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: star_pnt_before_delete
	if(function_exists('star_pnt_before_delete')) {
		$args = [];
		if(!star_pnt_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `star_pnt` WHERE `id`='{$selected_id}'", $eo);

	// hook: star_pnt_after_delete
	if(function_exists('star_pnt_after_delete')) {
		$args = [];
		star_pnt_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='star_pnt' AND `pkValue`='{$selected_id}'", $eo);
}

function star_pnt_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('star_pnt', $selected_id, 'edit')) return false;

	$data = [
		'name_of_the_candidate' => Request::val('name_of_the_candidate', ''),
		'institute' => Request::val('institute', ''),
		'workspace' => Request::val('workspace', ''),
		'year_and_department' => Request::val('year_and_department', ''),
		'project_title' => br2nl(Request::val('project_title', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('star_pnt', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: star_pnt_before_update
	if(function_exists('star_pnt_before_update')) {
		$args = ['old_data' => $old_data];
		if(!star_pnt_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'star_pnt',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="star_pnt_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('star_pnt', $data['selectedID'], calculated_fields()['star_pnt']);

	// hook: star_pnt_after_update
	if(function_exists('star_pnt_after_update')) {
		if($row = getRecord('star_pnt', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!star_pnt_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('star_pnt', $selected_id);
}

